// ============================================================
// Log Level Enum
// ============================================================

enum LogLevel {
  verbose(0, 'VERBOSE'),
  debug(1, 'DEBUG'),
  info(2, 'INFO'),
  warning(3, 'WARNING'),
  error(4, 'ERROR'),
  fatal(5, 'FATAL'),
  none(6, 'NONE');

  final int priority;
  final String label;
  const LogLevel(this.priority, this.label);

  bool operator >=(LogLevel other) => priority >= other.priority;
  bool operator >(LogLevel other) => priority > other.priority;
}

// ============================================================
// Log Entry
// ============================================================

class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final String category;
  final String message;
  final Map<String, dynamic>? metadata;
  final String? errorType;
  final String? stackTrace;
  final String? sessionId;
  final String? userId;

  LogEntry({
    required this.level,
    required this.category,
    required this.message,
    this.metadata,
    this.errorType,
    this.stackTrace,
    this.sessionId,
    this.userId,
  }) : timestamp = DateTime.now().toUtc();

  Map<String, dynamic> toJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.label,
        'category': category,
        'message': message,
        if (metadata != null && metadata!.isNotEmpty) 'metadata': metadata,
        if (errorType != null) 'error_type': errorType,
        if (stackTrace != null) 'stack_trace': stackTrace,
        if (sessionId != null) 'session_id': sessionId,
        if (userId != null) 'user_id': userId,
      };

  @override
  String toString() {
    final buf = StringBuffer();
    buf.write('[${timestamp.toIso8601String()}]');
    buf.write(' [${level.label}]');
    buf.write(' [$category]');
    buf.write(' $message');
    if (metadata != null && metadata!.isNotEmpty) {
      buf.write(' | metadata: ${jsonEncode(metadata)}');
    }
    if (errorType != null) {
      buf.write(' | error: $errorType');
    }
    if (stackTrace != null) {
      buf.write('\n$stackTrace');
    }
    return buf.toString();
  }
}

// ============================================================
// Sensitive Data Sanitizer
// ============================================================

class DataSanitizer {
  // Fields that should NEVER be logged
  static const _redactedFields = <String>{
    'password',
    'passwd',
    'pass',
    'secret',
    'token',
    'access_token',
    'refresh_token',
    'id_token',
    'api_key',
    'apikey',
    'api_secret',
    'authorization',
    'auth',
    'cookie',
    'set-cookie',
    'x-api-key',
    'x-auth-token',
    'credit_card',
    'card_number',
    'cvv',
    'cvc',
    'ssn',
    'social_security',
    'pin',
    'otp',
    'totp',
    'private_key',
    'signing_key',
  };

  // Fields containing PII that should be masked
  static const _piiFields = <String>{
    'email',
    'phone',
    'phone_number',
    'address',
    'date_of_birth',
    'dob',
    'name',
    'first_name',
    'last_name',
    'full_name',
  };

  static const String _redactedPlaceholder = '[REDACTED]';
  static const String _piiPrefix = '[MASKED]';

  /// Sanitize a map of data, removing sensitive fields
  static Map<String, dynamic> sanitizeMap(Map<String, dynamic> data) {
    final sanitized = <String, dynamic>{};
    for (final entry in data.entries) {
      final keyLower = entry.key.toLowerCase().replaceAll('-', '_');

      if (_redactedFields.contains(keyLower)) {
        sanitized[entry.key] = _redactedPlaceholder;
      } else if (_piiFields.contains(keyLower)) {
        sanitized[entry.key] = _maskPii(entry.value);
      } else if (entry.value is Map<String, dynamic>) {
        sanitized[entry.key] = sanitizeMap(entry.value as Map<String, dynamic>);
      } else if (entry.value is List) {
        sanitized[entry.key] = _sanitizeList(entry.value as List);
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  static List _sanitizeList(List items) {
    return items.map((item) {
      if (item is Map<String, dynamic>) {
        return sanitizeMap(item);
      }
      return item;
    }).toList();
  }

  /// Sanitize HTTP headers specifically
  static Map<String, String> sanitizeHeaders(Map<String, String> headers) {
    final sanitized = <String, String>{};
    for (final entry in headers.entries) {
      final keyLower = entry.key.toLowerCase().replaceAll('-', '_');
      if (_redactedFields.contains(keyLower)) {
        sanitized[entry.key] = _redactedPlaceholder;
      } else if (entry.key.toLowerCase() == 'authorization') {
        sanitized[entry.key] = _maskAuthHeader(entry.value);
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  static String _maskAuthHeader(String value) {
    if (value.toLowerCase().startsWith('bearer ')) {
      final token = value.substring(7);
      if (token.length > 8) {
        return 'Bearer ${token.substring(0, 4)}...${token.substring(token.length - 4)}';
      }
      return 'Bearer $_redactedPlaceholder';
    }
    if (value.toLowerCase().startsWith('basic ')) {
      return 'Basic $_redactedPlaceholder';
    }
    return _redactedPlaceholder;
  }

  static String _maskPii(dynamic value) {
    if (value == null) return '$_piiPrefix null';
    final str = value.toString();
    if (str.isEmpty) return '$_piiPrefix empty';

    // Email masking: j***@e***.com
    if (str.contains('@')) {
      final parts = str.split('@');
      final local = parts[0];
      final domain = parts.length > 1 ? parts[1] : '';
      final maskedLocal = local.isNotEmpty
          ? '${local[0]}${'*' * (local.length - 1).clamp(1, 5)}'
          : '*';
      final domainParts = domain.split('.');
      final maskedDomain = domainParts.isNotEmpty
          ? '${domainParts[0][0]}${'*' * (domainParts[0].length - 1).clamp(1, 5)}'
          : '*';
      final tld = domainParts.length > 1 ? '.${domainParts.last}' : '';
      return '$_piiPrefix $maskedLocal@$maskedDomain$tld';
    }

    // Generic masking: show first and last char
    if (str.length <= 2) return '$_piiPrefix ${'*' * str.length}';
    return '$_piiPrefix ${str[0]}${'*' * (str.length - 2)}${str[str.length - 1]}';
  }

  /// Sanitize a URL by removing query parameters that might contain secrets
  static String sanitizeUrl(String url) {
    try {
      final uri = Uri.parse(url);
      if (uri.queryParameters.isEmpty) return url;

      final sanitizedParams = <String, String>{};
      for (final entry in uri.queryParameters.entries) {
        final keyLower = entry.key.toLowerCase().replaceAll('-', '_');
        if (_redactedFields.contains(keyLower)) {
          sanitizedParams[entry.key] = _redactedPlaceholder;
        } else {
          sanitizedParams[entry.key] = entry.value;
        }
      }

      return uri.replace(queryParameters: sanitizedParams).toString();
    } catch (_) {
      return url;
    }
  }

  /// Attempt to sanitize a JSON string body
  static String sanitizeBody(String? body) {
    if (body == null || body.isEmpty) return '[empty]';
    try {
      final decoded = jsonDecode(body);
      if (decoded is Map<String, dynamic>) {
        return jsonEncode(sanitizeMap(decoded));
      }
      if (decoded is List) {
        return jsonEncode(_sanitizeList(decoded));
      }
      return body;
    } catch (_) {
      // Not JSON, truncate if too long
      if (body.length > 500) {
        return '${body.substring(0, 500)}... [truncated ${body.length} chars]';
      }
      return body;
    }
  }
}

// ============================================================
// Log Output Destinations
// ============================================================

abstract class LogOutput {
  Future<void> write(LogEntry entry);
  Future<void> flush();
  Future<void> dispose();
}

/// Console output using debugPrint (safe for Flutter, handles throttling)
class ConsoleLogOutput extends LogOutput {
  @override
  Future<void> write(LogEntry entry) async {
    // debugPrint handles message throttling and is safe for all platforms
    debugPrint(entry.toString());
  }

  @override
  Future<void> flush() async {}

  @override
  Future<void> dispose() async {}
}

/// File-based log output for on-device log storage
class FileLogOutput extends LogOutput {
  final String logDirectoryPath;
  final int maxFileSizeBytes;
  final int maxLogFiles;
  IOSink? _sink;
  File? _currentFile;
  int _currentSize = 0;

  FileLogOutput({
    required this.logDirectoryPath,
    this.maxFileSizeBytes = 5 * 1024 * 1024, // 5 MB
    this.maxLogFiles = 5,
  });

  Future<void> _ensureFile() async {
    if (_sink != null) return;

    final dir = Directory(logDirectoryPath);
    if (!await dir.exists()) {
      await dir.create(recursive: true);
    }

    await _rotateIfNeeded();

    final fileName =
        'app_log_${DateTime.now().toUtc().toIso8601String().replaceAll(':', '-')}.log';
    _currentFile = File('${dir.path}/$fileName');
    _sink = _currentFile!.openWrite(mode: FileMode.append);
    _currentSize = await _currentFile!.exists() ? await _currentFile!.length() : 0;
  }

  Future<void> _rotateIfNeeded() async {
    final dir = Directory(logDirectoryPath);
    final files = await dir
        .list()
        .where((entity) => entity is File && entity.path.endsWith('.log'))
        .cast<File>()
        .toList();

    files.sort((a, b) => a.path.compareTo(b.path));

    // Remove oldest files if we exceed max
    while (files.length >= maxLogFiles) {
      await files.removeAt(0).delete();
    }
  }

  @override
  Future<void> write(LogEntry entry) async {
    try {
      await _ensureFile();
      final line = '${jsonEncode(entry.toJson())}\n';
      _sink?.write(line);
      _currentSize += line.length;

      if (_currentSize >= maxFileSizeBytes) {
        await flush();
        await _sink?.close();
        _sink = null;
        _currentFile = null;
      }
    } catch (e) {
      debugPrint('[Logger] FileLogOutput error: $e');
    }
  }

  @override
  Future<void> flush() async {
    await _sink?.flush();
  }

  @override
  Future<void> dispose() async {
    await flush();
    await _sink?.close();
    _sink = null;
  }
}

/// Remote log output that batches and sends logs to a monitoring service
class RemoteLogOutput extends LogOutput {
  final String endpoint;
  final Duration batchInterval;
  final int maxBatchSize;
  final List<LogEntry> _buffer = [];
  Timer? _timer;
  final Map<String, String> _headers;

  RemoteLogOutput({
    required this.endpoint,
    this.batchInterval = const Duration(seconds: 30),
    this.maxBatchSize = 100,
    Map<String, String>? headers,
  }) : _headers = headers ?? {} {
    _timer = Timer.periodic(batchInterval, (_) => flush());
  }

  @override
  Future<void> write(LogEntry entry) async {
    _buffer.add(entry);
    if (_buffer.length >= maxBatchSize) {
      await flush();
    }
  }

  @override
  Future<void> flush() async {
    if (_buffer.isEmpty) return;

    final batch = List<LogEntry>.from(_buffer);
    _buffer.clear();

    try {
      final client = HttpClient();
      final request = await client.postUrl(Uri.parse(endpoint));
      _headers.forEach((key, value) {
        request.headers.set(key, value);
      });
      request.headers.set('Content-Type', 'application/json');
      request.write(jsonEncode({
        'logs': batch.map((e) => e.toJson()).toList(),
      }));
      final response = await request.close();
      await response.drain();
      client.close();
    } catch (e) {
      debugPrint('[Logger] RemoteLogOutput send error: $e');
      // Put failed entries back (with limit to avoid memory issues)
      if (_buffer.length + batch.length <= maxBatchSize * 3) {
        _buffer.insertAll(0, batch);
      }
    }
  }

  @override
  Future<void> dispose() async {
    _timer?.cancel();
    await flush();
  }
}

// ============================================================
// Environment Configuration
// ============================================================

enum AppEnvironment { development, staging, production }

class LogConfig {
  final AppEnvironment environment;
  final LogLevel minimumLevel;
  final List<LogOutput> outputs;
  final bool sanitizeSensitiveData;
  final bool includeStackTraces;
  final int maxBodyLogLength;

  const LogConfig({
    required this.environment,
    required this.minimumLevel,
    required this.outputs,
    this.sanitizeSensitiveData = true,
    this.includeStackTraces = true,
    this.maxBodyLogLength = 1000,
  });

  /// Development: verbose console logging, still sanitized
  factory LogConfig.development() => LogConfig(
        environment: AppEnvironment.development,
        minimumLevel: LogLevel.verbose,
        outputs: [ConsoleLogOutput()],
        sanitizeSensitiveData: true, // ALWAYS sanitize, even in dev
        includeStackTraces: true,
        maxBodyLogLength: 5000,
      );

  /// Staging: info level, console + file
  factory LogConfig.staging({required String logDir}) => LogConfig(
        environment: AppEnvironment.staging,
        minimumLevel: LogLevel.debug,
        outputs: [
          ConsoleLogOutput(),
          FileLogOutput(logDirectoryPath: logDir),
        ],
        sanitizeSensitiveData: true,
        includeStackTraces: true,
        maxBodyLogLength: 2000,
      );

  /// Production: warning+ to remote, info+ to file, no console
  factory LogConfig.production({
    required String logDir,
    required String remoteEndpoint,
    Map<String, String>? remoteHeaders,
  }) =>
      LogConfig(
        environment: AppEnvironment.production,
        minimumLevel: LogLevel.info,
        outputs: [
          FileLogOutput(logDirectoryPath: logDir, maxLogFiles: 3),
          RemoteLogOutput(
            endpoint: remoteEndpoint,
            headers: remoteHeaders,
          ),
        ],
        sanitizeSensitiveData: true,
        includeStackTraces: true,
        maxBodyLogLength: 500,
      );
}

// ============================================================
// Main Logger
// ============================================================

class AppLogger {
  static AppLogger? _instance;
  late LogConfig _config;
  String? _sessionId;
  String? _userId;

  AppLogger._();

  static AppLogger get instance {
    _instance ??= AppLogger._();
    return _instance!;
  }

  void initialize(LogConfig config, {String? sessionId}) {
    _config = config;
    _sessionId = sessionId;
  }

  void setUserId(String? userId) {
    _userId = userId;
  }

  void setSessionId(String sessionId) {
    _sessionId = sessionId;
  }

  bool _shouldLog(LogLevel level) => level >= _config.minimumLevel;

  Future<void> _log(LogEntry entry) async {
    if (!_shouldLog(entry.level)) return;
    for (final output in _config.outputs) {
      try {
        await output.write(entry);
      } catch (e) {
        debugPrint('[Logger] Output error: $e');
      }
    }
  }

  // ---- General Logging Methods ----

  void verbose(String category, String message, {Map<String, dynamic>? metadata}) {
    _log(LogEntry(
      level: LogLevel.verbose,
      category: category,
      message: message,
      metadata: metadata != null ? DataSanitizer.sanitizeMap(metadata) : null,
      sessionId: _sessionId,
      userId: _userId,
    ));
  }

  void debug(String category, String message, {Map<String, dynamic>? metadata}) {
    _log(LogEntry(
      level: LogLevel.debug,
      category: category,
      message: message,
      metadata: metadata != null ? DataSanitizer.sanitizeMap(metadata) : null,
      sessionId: _sessionId,
      userId: _userId,
    ));
  }

  void info(String category, String message, {Map<String, dynamic>? metadata}) {
    _log(LogEntry(
      level: LogLevel.info,
      category: category,
      message: message,
      metadata: metadata != null ? DataSanitizer.sanitizeMap(metadata) : null,
      sessionId: _sessionId,
      userId: _userId,
    ));
  }

  void warning(String category, String message,
      {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) {
    _log(LogEntry(
      level: LogLevel.warning,
      category: category,
      message: message,
      metadata: metadata != null ? DataSanitizer.sanitizeMap(metadata) : null,
      errorType: error?.runtimeType.toString(),
      stackTrace:
          _config.includeStackTraces ? stackTrace?.toString() : null,
      sessionId: _sessionId,
      userId: _userId,
    ));
  }

  void error(String category, String message,
      {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) {
    _log(LogEntry(
      level: LogLevel.error,
      category: category,
      message: message,
      metadata: metadata != null ? DataSanitizer.sanitizeMap(metadata) : null,
      errorType: error?.runtimeType.toString(),
      stackTrace:
          _config.includeStackTraces ? stackTrace?.toString() : null,
      sessionId: _sessionId,
      userId: _userId,
    ));
  }

  void fatal(String category, String message,
      {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) {
    _log(LogEntry(
      level: LogLevel.fatal,
      category: category,
      message: message,
      metadata: metadata != null ? DataSanitizer.sanitizeMap(metadata) : null,
      errorType: error?.runtimeType.toString(),
      stackTrace:
          _config.includeStackTraces ? stackTrace?.toString() : null,
      sessionId: _sessionId,
      userId: _userId,
    ));
  }

  Future<void> flush() async {
    for (final output in _config.outputs) {
      await output.flush();
    }
  }

  Future<void> dispose() async {
    for (final output in _config.outputs) {
      await output.dispose();
    }
  }
}

// ============================================================
// HTTP Request/Response Logger
// ============================================================

class HttpLogger {
  static const String _category = 'HTTP';
  final AppLogger _logger = AppLogger.instance;

  /// Log an outgoing HTTP request (sanitized)
  void logRequest({
    required String method,
    required String url,
    Map<String, String>? headers,
    String? body,
    String? requestId,
  }) {
    final sanitizedUrl = DataSanitizer.sanitizeUrl(url);
    final sanitizedHeaders =
        headers != null ? DataSanitizer.sanitizeHeaders(headers) : null;
    final sanitizedBody = DataSanitizer.sanitizeBody(body);

    _logger.info(_category, '$method $sanitizedUrl', metadata: {
      'direction': 'request',
      'method': method,
      'url': sanitizedUrl,
      if (sanitizedHeaders != null) 'headers': sanitizedHeaders,
      if (body != null) 'body_preview': sanitizedBody,
      if (requestId != null) 'request_id': requestId,
    });
  }

  /// Log an HTTP response (sanitized)
  void logResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, String>? headers,
    String? body,
    Duration? duration,
    String? requestId,
  }) {
    final sanitizedUrl = DataSanitizer.sanitizeUrl(url);
    final level = _levelForStatusCode(statusCode);
    final sanitizedBody = DataSanitizer.sanitizeBody(body);
    final sanitizedHeaders =
        headers != null ? DataSanitizer.sanitizeHeaders(headers) : null;

    _logger._log(LogEntry(
      level: level,
      category: _category,
      message: '$method $sanitizedUrl -> $statusCode (${duration?.inMilliseconds ?? '?'}ms)',
      metadata: DataSanitizer.sanitizeMap({
        'direction': 'response',
        'method': method,
        'url': sanitizedUrl,
        'status_code': statusCode,
        if (sanitizedHeaders != null) 'headers': sanitizedHeaders,
        if (body != null) 'body_preview': sanitizedBody,
        if (duration != null) 'duration_ms': duration.inMilliseconds,
        if (requestId != null) 'request_id': requestId,
      }),
      sessionId: AppLogger.instance._sessionId,
      userId: AppLogger.instance._userId,
    ));
  }

  /// Log an HTTP error
  void logError({
    required String method,
    required String url,
    required Object error,
    StackTrace? stackTrace,
    Duration? duration,
    String? requestId,
  }) {
    final sanitizedUrl = DataSanitizer.sanitizeUrl(url);

    _logger.error(
      _category,
      '$method $sanitizedUrl -> ERROR: ${error.runtimeType}',
      metadata: {
        'method': method,
        'url': sanitizedUrl,
        'error_message': error.toString(),
        if (duration != null) 'duration_ms': duration.inMilliseconds,
        if (requestId != null) 'request_id': requestId,
      },
      error: error,
      stackTrace: stackTrace,
    );
  }

  LogLevel _levelForStatusCode(int code) {
    if (code >= 200 && code < 300) return LogLevel.info;
    if (code >= 300 && code < 400) return LogLevel.info;
    if (code >= 400 && code < 500) return LogLevel.warning;
    return LogLevel.error;
  }
}

// ============================================================
// Authentication Flow Logger
// ============================================================

class AuthLogger {
  static const String _category = 'AUTH';
  final AppLogger _logger = AppLogger.instance;

  void logLoginAttempt({required String method, String? email}) {
    _logger.info(_category, 'Login attempt via $method', metadata: {
      'method': method,
      // Email is PII - it will be masked by the sanitizer
      if (email != null) 'email': email,
    });
  }

  void logLoginSuccess({required String method, required String userId}) {
    _logger.info(_category, 'Login successful via $method', metadata: {
      'method': method,
      'user_id': userId,
      // NOTE: We log user_id (not sensitive) but NEVER tokens or passwords
    });
  }

  void logLoginFailure({
    required String method,
    required String reason,
    String? email,
    Object? error,
  }) {
    _logger.warning(_category, 'Login failed via $method: $reason', metadata: {
      'method': method,
      'failure_reason': reason,
      if (email != null) 'email': email,
      // NOTE: We log the failure reason (e.g., "invalid_credentials")
      // but NEVER the actual password that was attempted
    });
  }

  void logTokenRefresh({required bool success, String? reason}) {
    if (success) {
      _logger.debug(_category, 'Token refreshed successfully');
    } else {
      _logger.warning(_category, 'Token refresh failed', metadata: {
        if (reason != null) 'reason': reason,
      });
    }
  }

  void logLogout({required String userId, required String reason}) {
    _logger.info(_category, 'User logged out', metadata: {
      'user_id': userId,
      'reason': reason,
    });
  }

  void logSessionExpired({required String userId}) {
    _logger.info(_category, 'Session expired', metadata: {
      'user_id': userId,
    });
  }

  void logPermissionDenied({
    required String userId,
    required String resource,
    required String action,
  }) {
    _logger.warning(_category, 'Permission denied', metadata: {
      'user_id': userId,
      'resource': resource,
      'action': action,
    });
  }
}

