    required int fromVersion,
    required int toVersion,
    required bool success,
    Duration? duration,
    Object? error,
  }) {
    if (success) {
      _logger.info(_category, 'Migration v$fromVersion -> v$toVersion completed', metadata: {
        'from_version': fromVersion,
        'to_version': toVersion,
        if (duration != null) 'duration_ms': duration.inMilliseconds,
      });
    } else {
      _logger.error(
        _category,
        'Migration v$fromVersion -> v$toVersion FAILED',
        metadata: {
          'from_version': fromVersion,
          'to_version': toVersion,
          if (duration != null) 'duration_ms': duration.inMilliseconds,
        },
        error: error,
      );
    }
  }

  void logConnectionEvent({required String event, Map<String, dynamic>? details}) {
    _logger.info(_category, 'Connection: $event', metadata: details);
  }
}

// ============================================================
// User Interaction Logger
// ============================================================

class InteractionLogger {
  static const String _category = 'USER_INTERACTION';
  final AppLogger _logger = AppLogger.instance;

  void logScreenView({required String screenName, Map<String, dynamic>? parameters}) {
    _logger.info(_category, 'Screen viewed: $screenName', metadata: {
      'screen': screenName,
      if (parameters != null)
        ...DataSanitizer.sanitizeMap(parameters),
    });
  }

  void logButtonTap({required String buttonId, String? screen}) {
    _logger.debug(_category, 'Button tapped: $buttonId', metadata: {
      'button_id': buttonId,
      if (screen != null) 'screen': screen,
    });
  }

  void logUserAction({
    required String action,
    String? screen,
    Map<String, dynamic>? details,
  }) {
    _logger.info(_category, 'User action: $action', metadata: {
      'action': action,
      if (screen != null) 'screen': screen,
      if (details != null) ...DataSanitizer.sanitizeMap(details),
    });
  }

  void logFormSubmission({
    required String formName,
    required bool success,
    List<String>? validationErrors,
  }) {
    if (success) {
      _logger.info(_category, 'Form submitted: $formName', metadata: {
        'form': formName,
        'success': true,
        // NOTE: We NEVER log form field values, only the form name and result
      });
    } else {
      _logger.debug(_category, 'Form validation failed: $formName', metadata: {
        'form': formName,
        'success': false,
        // Log which fields had errors, but not the values
        if (validationErrors != null) 'validation_error_fields': validationErrors,
      });
    }
  }

  void logNavigation({required String from, required String to}) {
    _logger.debug(_category, 'Navigation: $from -> $to', metadata: {
      'from': from,
      'to': to,
    });
  }

  void logSearch({required String context, int? resultCount}) {
    // Log that a search happened and result count, but NOT the search query
    // (could contain PII like names, SSNs, etc.)
    _logger.info(_category, 'Search performed in $context', metadata: {
      'context': context,
      if (resultCount != null) 'result_count': resultCount,
    });
  }
}

// ============================================================
// App Health / Performance Logger
// ============================================================

class HealthLogger {
  static const String _category = 'HEALTH';
  final AppLogger _logger = AppLogger.instance;

  void logAppLifecycle(String state) {
    _logger.info(_category, 'App lifecycle: $state');
  }

  void logPerformanceMetric({
    required String name,
    required Duration duration,
    Map<String, dynamic>? attributes,
  }) {
    final level = duration.inMilliseconds > 3000 ? LogLevel.warning : LogLevel.info;
    _logger._log(LogEntry(
      level: level,
      category: _category,
      message: 'Performance: $name took ${duration.inMilliseconds}ms',
      metadata: {
        'metric_name': name,
        'duration_ms': duration.inMilliseconds,
        if (attributes != null) ...attributes,
      },
      sessionId: _logger._sessionId,
      userId: _logger._userId,
    ));
  }

  void logMemoryWarning() {
    _logger.warning(_category, 'Memory warning received');
  }

  void logFrameDrop({required int droppedFrames, required Duration duration}) {
    _logger.warning(_category, 'Frame drops detected', metadata: {
      'dropped_frames': droppedFrames,
      'duration_ms': duration.inMilliseconds,
    });
  }

  void logStartup({required Duration duration, Map<String, dynamic>? metrics}) {
    _logger.info(_category, 'App startup completed in ${duration.inMilliseconds}ms',
        metadata: {
          'duration_ms': duration.inMilliseconds,
          if (metrics != null) ...metrics,
        });
  }

  void logCrash({
    required Object error,
    required StackTrace stackTrace,
    bool isFatal = true,
  }) {
    _logger.fatal(
      _category,
      'App ${isFatal ? "FATAL" : "non-fatal"} crash: ${error.runtimeType}',
      metadata: {
        'is_fatal': isFatal,
        'error_message': error.toString(),
      },
      error: error,
      stackTrace: stackTrace,
    );
  }
}

// ============================================================
// Convenience Facade
// ============================================================

class Log {
  static final http = HttpLogger();
  static final auth = AuthLogger();
  static final db = DatabaseLogger();
  static final ui = InteractionLogger();
  static final health = HealthLogger();
  static final _logger = AppLogger.instance;

  // General purpose shortcuts
  static void v(String category, String msg, {Map<String, dynamic>? data}) =>
      _logger.verbose(category, msg, metadata: data);

  static void d(String category, String msg, {Map<String, dynamic>? data}) =>
      _logger.debug(category, msg, metadata: data);

  static void i(String category, String msg, {Map<String, dynamic>? data}) =>
      _logger.info(category, msg, metadata: data);

  static void w(String category, String msg,
          {Map<String, dynamic>? data, Object? error, StackTrace? stack}) =>
      _logger.warning(category, msg,
          metadata: data, error: error, stackTrace: stack);

  static void e(String category, String msg,
          {Map<String, dynamic>? data, Object? error, StackTrace? stack}) =>
      _logger.error(category, msg,
          metadata: data, error: error, stackTrace: stack);

  static void f(String category, String msg,
          {Map<String, dynamic>? data, Object? error, StackTrace? stack}) =>
      _logger.fatal(category, msg,
          metadata: data, error: error, stackTrace: stack);
}

// ============================================================
// Usage Example / Main
// ============================================================

void main() {
  // ---- Initialize for the appropriate environment ----

  // For development:
  AppLogger.instance.initialize(LogConfig.development());

  // For production (uncomment):
  // AppLogger.instance.initialize(LogConfig.production(
  //   logDir: '/data/user/0/com.example.app/files/logs',
  //   remoteEndpoint: 'https://logging.example.com/api/v1/logs',
  //   remoteHeaders: {'X-App-Key': 'your-logging-service-key'},
  // ));

  AppLogger.instance.setSessionId('sess_abc123');

  // ---- HTTP Logging ----
  Log.http.logRequest(
    method: 'POST',
    url: 'https://api.example.com/v1/users?api_key=secret123',
    headers: {
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.very_long_token_here',
      'Content-Type': 'application/json',
    },
    body: jsonEncode({
      'email': 'john.doe@example.com',
      'password': 'super_secret_password',
      'name': 'John Doe',
      'preferences': {'theme': 'dark'},
    }),
    requestId: 'req_001',
  );

  Log.http.logResponse(
    method: 'POST',
    url: 'https://api.example.com/v1/users',
    statusCode: 201,
    body: jsonEncode({
      'id': 'usr_123',
      'email': 'john.doe@example.com',
      'token': 'new_access_token_here',
      'refresh_token': 'new_refresh_token_here',
    }),
    duration: const Duration(milliseconds: 342),
    requestId: 'req_001',
  );

  // ---- Auth Logging ----
  Log.auth.logLoginAttempt(method: 'email', email: 'john.doe@example.com');
  Log.auth.logLoginSuccess(method: 'email', userId: 'usr_123');
  AppLogger.instance.setUserId('usr_123');

  Log.auth.logTokenRefresh(success: true);
  Log.auth.logPermissionDenied(
    userId: 'usr_123',
    resource: 'admin_panel',
    action: 'read',
  );

  // ---- Database Logging ----
  Log.db.logQuery(
    operation: 'INSERT',
    table: 'user_settings',
    duration: const Duration(milliseconds: 12),
    rowsAffected: 1,
    parameters: {
      'user_id': 'usr_123',
      'theme': 'dark',
      'api_key': 'should_not_appear',
    },
  );

  Log.db.logMigration(
    fromVersion: 3,
    toVersion: 4,
    success: true,
    duration: const Duration(milliseconds: 450),
  );

  // ---- User Interaction Logging ----
  Log.ui.logScreenView(screenName: 'ProfileScreen');
  Log.ui.logButtonTap(buttonId: 'save_profile', screen: 'ProfileScreen');
  Log.ui.logFormSubmission(
    formName: 'profile_edit',
    success: false,
    validationErrors: ['phone_number', 'address'],
  );
  Log.ui.logSearch(context: 'products', resultCount: 42);

  // ---- Health / Performance Logging ----
  Log.health.logStartup(
    duration: const Duration(milliseconds: 1200),
    metrics: {'cold_start': true, 'cached_data': false},
  );
  Log.health.logPerformanceMetric(
    name: 'image_gallery_load',
    duration: const Duration(milliseconds: 3500),
  );
  Log.health.logAppLifecycle('paused');

  // ---- General Logging ----
  Log.i('FEATURE_FLAG', 'Feature flags loaded', data: {
    'new_checkout': true,
    'dark_mode_v2': false,
  });

  Log.w('PAYMENT', 'Payment retry needed', data: {
    'attempt': 2,
    'order_id': 'ord_456',
    // Card numbers would be sanitized if they somehow ended up here
    'card_number': '4111111111111111',
  });

  // Demonstrate that sensitive data IS sanitized:
  debugPrint('\n=== Sanitization Demo ===');
  final testData = {
    'username': 'jdoe',
    'password': 'my_secret_pw',
    'token': 'abc123xyz',
    'email': 'jane.doe@company.com',
    'phone': '+1-555-123-4567',
    'profile': {
      'name': 'Jane Doe',
      'api_key': 'key_abc123',
      'preferences': {'theme': 'dark'},
    },
  };
  debugPrint('Original: ${jsonEncode(testData)}');
  debugPrint('Sanitized: ${jsonEncode(DataSanitizer.sanitizeMap(testData))}');

  debugPrint('\n=== URL Sanitization Demo ===');
  const testUrl = 'https://api.example.com/data?user=john&token=secret123&page=1';
  debugPrint('Original: $testUrl');
  debugPrint('Sanitized: ${DataSanitizer.sanitizeUrl(testUrl)}');

  debugPrint('\n=== Header Sanitization Demo ===');
  final testHeaders = {
    'Authorization': 'Bearer eyJhbGciOiJIUzI1NiJ9.longTokenHere.signature',
    'Content-Type': 'application/json',
    'X-Api-Key': 'my_super_secret_key',
    'Accept': '*/*',
  };
  debugPrint('Original: $testHeaders');
  debugPrint('Sanitized: ${DataSanitizer.sanitizeHeaders(testHeaders)}');

  // Clean up
  AppLogger.instance.dispose();
}